dslRuleAfterChange:
A hypothetical DSL rule might look like:

if ($this == $type)
=> if ($this == $type) //$IDENTITY-COMPARISON$
;;

However, this functionality (inserting comments into the matched Java code via the replacement pattern) is not supported by the current DSL.

dslRule:
/*!id: jdt.api.deprecated.getdeclaredmodifiers*/
/*!description: Replace deprecated ITypeBinding.getDeclaredModifiers() with getModifiers().*/
/*!severity: warning*/
org.eclipse.jdt.core.dom.ITypeBinding.$typeBinding.getDeclaredModifiers()
:: instanceof($typeBinding, "org.eclipse.jdt.core.dom.ITypeBinding")
=> $typeBinding.getModifiers()
;;

@id: jdt.internal.astrewriteanalyzer.rewriteextradimensionsinfo.whitespace
@severity: info
rewriteNodeList($node, $property, $pos, " ", " ")
=> rewriteNodeList($node, $property, $pos, " ", "")
;;

@id: jdt.internal.astrewriteanalyzer.arraytype.visit.to.helper
@severity: info
rewriteNodeList($node, org.eclipse.jdt.core.dom.ArrayType.DIMENSIONS_PROPERTY, $pos, org.eclipse.jdt.internal.core.dom.rewrite.Util.EMPTY_STRING, " ")
:: inClass("org.eclipse.jdt.internal.core.dom.rewrite.ASTRewriteAnalyzer") && inMethod("visit")
=> rewriteArrayTypeDimensions($node, $pos)
;;

@id: jdt.internal.astrewriteflattener.arraytype.visitlist.whitespace
@severity: info
visitList($node, org.eclipse.jdt.core.dom.ArrayType.DIMENSIONS_PROPERTY, java.lang.String.valueOf(' '), org.eclipse.jdt.internal.core.dom.rewrite.Util.EMPTY_STRING, java.lang.String.valueOf(' '))
:: inClass("org.eclipse.jdt.internal.core.dom.rewrite.ASTRewriteFlattener")
=> visitList($node, org.eclipse.jdt.core.dom.ArrayType.DIMENSIONS_PROPERTY, org.eclipse.jdt.internal.core.dom.rewrite.Util.EMPTY_STRING, org.eclipse.jdt.internal.core.dom.rewrite.Util.EMPTY_STRING, org.eclipse.jdt.internal.core.dom.rewrite.Util.EMPTY_STRING)
;;

/*!id: jdt.internal.compiler.lambdaexpression.arguments-to-method*/
/*!description: Updates internal JDT ASTConverter to use lambda.arguments() method instead of direct field access on LambdaExpression.*/
/*!severity: info*/
/*!tags: jdt, internal, refactoring*/
$lambda.arguments :: instanceof($lambda, "org.eclipse.jdt.internal.compiler.ast.LambdaExpression")
=> $lambda.arguments()
;;

/*!id: jdt.internal.compiler.lambdaexpression.body-to-method*/
/*!description: Updates internal JDT ASTConverter to use lambda.body() method instead of direct field access on LambdaExpression.*/
/*!severity: info*/
/*!tags: jdt, internal, refactoring*/
$lambda.body :: instanceof($lambda, "org.eclipse.jdt.internal.compiler.ast.LambdaExpression")
=> $lambda.body()
;;

/*!id: jdt.internal.astconverter.initial-sourcestart-fix*/
/*!description: Fixes an internal bug in ASTConverter by correctly initializing 'sourceStart' variable and updating argument passed to 'convertToArray'.*/
/*!severity: info*/
int $sourceStart = -1;
:: inClass("org.eclipse.jdt.core.dom.ASTConverter") && inMethod("convert")
=> int $sourceStart = typeReference.sourceStart;
;;

@id: jdt.internal.astconverter.converttoarray.argument.fix
@severity: info
this.convertToArray($type, $sourceStart, -1, $dimensions, $annotations)
:: inClass("org.eclipse.jdt.core.dom.ASTConverter") && inMethod("convert")
=> this.convertToArray($type, $sourceStart, typeReference.sourceEnd - $sourceStart + 1, $dimensions, $annotations)
;;

@id: jdt.internal.typebinding.gettypedeclaration.unannotated
@description: Updates internal JDT TypeBinding.getTypeDeclaration() to strip type annotations by returning the unannotated binding.
@severity: info
this :: inClass("org.eclipse.jdt.core.dom.TypeBinding") && inMethod("getTypeDeclaration")
=> this.resolver.getTypeBinding(this.binding.unannotated())
;;
